import time
import logging
from typing import Generator, Dict, Any
import openai  # Make sure to install: pip install openai

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

chatgpt_quick_start = """
You are a helpful AI assistant optimized for clarity and action.
Provide comprehensive, well-structured responses that balance depth with practical utility.
"""

balance_check = """
Before responding, assess:
1. Is this helpful without being overwhelming?
2. Is this accurate without unnecessary complexity?
3. Is this actionable with clear next steps?
"""

class ChatGPTOptimizer:
    def __init__(self, api_key: str = None):
        self.current_mode = "balanced"
        if api_key:
            openai.api_key = api_key
        self.retry_count = 0

    def _infer_mode(self, text: str) -> str:
        """Enhanced mode inference with weighted keywords"""
        q = text.lower()
        mode_scores = {
            "technical": sum(1 for k in ["code", "technical", "regex", "api", "debug", "script", "function", "class"] if k in q),
            "analytical": sum(1 for k in ["analysis", "structured", "reasoning", "framework", "logic", "legal", "argument", "evaluate"] if k in q),
            "creative": sum(1 for k in ["creative", "unconventional", "story", "metaphor", "brainstorm", "idea", "innovative"] if k in q)
        }

        max_score = max(mode_scores.values())
        if max_score > 0:
            return max(mode_scores, key=mode_scores.get)
        return "balanced"

    def _build_system_prompt(self, mode: str) -> str:
        """Build mode-specific system prompts"""
        mode_prompts = {
            "technical": "You are a technical expert. Provide precise, code-focused answers with examples. Include both implementation details and best practices.",
            "analytical": "You are an analytical thinker. Structure responses with clear frameworks, evidence-based reasoning, and logical progression.",
            "creative": "You are a creative problem-solver. Offer innovative perspectives, multiple angles, and unconventional solutions.",
            "balanced": "You are a versatile assistant. Balance depth with accessibility, providing comprehensive yet understandable responses."
        }
        return mode_prompts.get(mode, mode_prompts["balanced"])

    def optimize_chatgpt_response(self, prompt: str, desired_output_style: str = "balanced", 
                                stream: bool = False, max_retries: int = 3) -> Any:
        """Main optimization method with robust error handling"""
        self.current_mode = self._infer_mode(f"{prompt} {desired_output_style}")

        engineered_prompt = f"""
ORIGINAL_PROMPT: {prompt}

RESPONSE_REQUIREMENTS:
- Mode: {self.current_mode.upper()}
- Style: {desired_output_style}
- Structure: Clear -> Detailed -> Actionable

{balance_check}

Please provide a response that follows this protocol.
"""

        try:
            if stream:
                return self._stream_with_backoff(engineered_prompt, max_retries)
            else:
                raw_response = self._retry_with_backoff(engineered_prompt, max_retries)
                return self._structure_into_protocol(raw_response)

        except Exception as e:
            logger.error(f"Final failure after {max_retries} retries: {str(e)}")
            return self._fallback_response(prompt)

    def _retry_with_backoff(self, prompt: str, max_retries: int) -> str:
        """Exponential backoff with proper error logging"""
        last_exception = None

        for attempt in range(max_retries):
            try:
                logger.info(f"API attempt {attempt + 1}/{max_retries}")
                response = self._call_openai_api(prompt, stream=False)
                self.retry_count = 0  # Reset on success
                return response

            except Exception as e:
                last_exception = e
                logger.warning(f"Attempt {attempt + 1} failed: {str(e)}")

                if attempt < max_retries - 1:
                    backoff_time = 2 ** attempt  # Exponential: 1, 2, 4, 8...
                    logger.info(f"Backing off for {backoff_time} seconds...")
                    time.sleep(backoff_time)

        raise last_exception  # Re-raise last exception after all retries

    def _stream_with_backoff(self, prompt: str, max_retries: int) -> Generator[str, None, None]:
        """Streaming version with backoff and proper generator behavior"""
        last_exception = None

        for attempt in range(max_retries):
            try:
                logger.info(f"Streaming API attempt {attempt + 1}/{max_retries}")

                for chunk in self._call_openai_api(prompt, stream=True):
                    yield chunk

                self.retry_count = 0
                return  # Success - exit generator

            except Exception as e:
                last_exception = e
                logger.warning(f"Streaming attempt {attempt + 1} failed: {str(e)}")

                if attempt < max_retries - 1:
                    backoff_time = 2 ** attempt
                    logger.info(f"Stream backing off for {backoff_time} seconds...")
                    time.sleep(backoff_time)

        # If all retries failed, yield error message
        yield f"Error: Failed after {max_retries} retries. {str(last_exception)}"

    def _call_openai_api(self, prompt: str, stream: bool = False) -> Any:
        """Real OpenAI API integration with proper streaming handling"""
        try:
            system_prompt = self._build_system_prompt(self.current_mode)

            response = openai.ChatCompletion.create(
                model="gpt-3.5-turbo",  # or "gpt-4"
                messages=[
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": prompt}
                ],
                stream=stream,
                temperature=0.7,
                max_tokens=1500
            )

            if stream:
                return self._handle_streaming_response(response)
            else:
                return response.choices[0].message.content

        except Exception as e:
            logger.error(f"OpenAI API error: {str(e)}")
            raise  # Re-raise for retry logic

    def _handle_streaming_response(self, response) -> Generator[str, None, None]:
        """Properly handle OpenAI streaming response"""
        for chunk in response:
            delta = chunk.choices[0].delta
            if hasattr(delta, 'content') and delta.content:
                yield delta.content

    def _structure_into_protocol(self, text: str) -> Dict[str, str]:
        """Enhanced parsing with better error recovery"""
        try:
            # Improved parsing logic
            lines = text.strip().split('\n')
            sections = {
                "Direct Answer": "",
                "Supporting Details": "", 
                "Action Steps": "",
                "Raw Response": text  # Always include raw for fallback
            }

            current_section = "Direct Answer"
            for line in lines:
                line_lower = line.lower().strip()

                if "supporting detail" in line_lower or "explanation" in line_lower:
                    current_section = "Supporting Details"
                elif "action step" in line_lower or "next step" in line_lower:
                    current_section = "Action Steps"
                elif line.strip() and not line_lower.startswith(('supporting', 'action')):
                    sections[current_section] += line + '\n'

            # Clean up sections
            for key in sections:
                if key != "Raw Response":
                    sections[key] = sections[key].strip()

            return sections

        except Exception as e:
            logger.error(f"Protocol structuring failed: {str(e)}")
            return {
                "Direct Answer": text,
                "Supporting Details": "Structure parsing failed",
                "Action Steps": "Please review raw response",
                "Raw Response": text
            }

    def _fallback_response(self, prompt: str) -> Dict[str, str]:
        """Graceful fallback when all retries fail"""
        return {
            "Direct Answer": "I apologize, but I'm unable to process your request at the moment due to technical difficulties.",
            "Supporting Details": f"Original prompt: {prompt}",
            "Action Steps": "1. Please try again later\n2. Check your API configuration\n3. Verify network connectivity",
            "Error": "Service temporarily unavailable"
        }

# ===== TESTING THE ENHANCED OPTIMIZER =====

def test_optimizer():
    """Comprehensive test function"""

    # Mock version for testing without API key
    class MockOptimizer(ChatGPTOptimizer):
        def _call_openai_api(self, prompt: str, stream: bool = False):
            if stream:
                def mock_stream():
                    responses = [
                        "Direct Answer: This is a mock streaming response.\n\n",
                        "Supporting Details: The system is working correctly with streaming.\n\n", 
                        "Action Steps: 1. Test complete 2. All systems operational"
                    ]
                    for resp in responses:
                        time.sleep(0.1)  # Simulate streaming delay
                        yield resp
                return mock_stream()
            else:
                return f"""Direct Answer: Mock response for testing.

Supporting Details: This simulates a successful API call with proper structure parsing. Original prompt was: {prompt}

Action Steps: 1. Verify the structure 2. Test retry logic 3. Implement real API"""

    print("=== Testing Enhanced ChatGPT Optimizer ===")

    # Test non-streaming
    opt = MockOptimizer()
    result = opt.optimize_chatgpt_response(
        "Explain constitutional prima facie analysis for legal cases", 
        "analytical"
    )
    print("NON-STREAMING RESULT:")
    for key, value in result.items():
        if key != "Raw Response":  # Skip raw for cleaner output
            print(f"\n{key}:\n{value}")

    # Test streaming
    print("\n=== STREAMING TEST ===")
    for chunk in opt.optimize_chatgpt_response(
        "Debug regex for legal document parsing", 
        "technical", 
        stream=True
    ):
        print(chunk, end='', flush=True)

if __name__ == "__main__":
    test_optimizer()

